    local OlOlO0II000=(O0lO0l0OlII-((O0I0llIIOOl+OI00OOll0l0)%256))%256
    OIOlIO0Illl[OI00OOll0l0]=string.char(OIOlO0l00IO(OlOlO0II000,OlllOO0OOO0))
end
local OllO0l0OOI0=table.concat(OIOlIO0Illl)
